Result<int> require_positive_int_arg(double v, const char* fn, const char* arg_name) {
    const int n = static_cast<int>(v);
    if (n < 1 || v != n) {
        return std::unexpected(DomainError{
            fn, std::string("expected positive integer ") + arg_name});
    }
    return n;
}

