    const geo::Point2D p0{p0x, p0y};
    const geo::Vec2D m0{m0x, m0y};
    const geo::Point2D p1{p1x, p1y};
    const geo::Vec2D m1{m1x, m1y};
    const geo::Point2D p = geo::hermite_curve(p0, m0, p1, m1, t);
