Result<std::vector<uint8_t>> parse_hex_arg_allow_empty(const std::string& text, const char* fn,
                                                      const char* arg_name) {
    std::string hex;
    if (!parse_quoted_string(text, hex)) {
        hex = trim_copy(text);
    }
    if (hex.empty()) {
        return std::vector<uint8_t>{};
    }
    return parse_hex_arg(text, fn, arg_name);
}

