Result<Matrix<double>> complex_vec_to_re_im_matrix(const std::vector<std::complex<double>>& z,
                                                   const char* fn) {
    if (z.empty()) {
        return std::unexpected(DomainError{fn, "transform failed"});
    }
    Matrix<double> out(z.size(), 2);
    for (size_t i = 0; i < z.size(); ++i) {
        out(i, 0) = z[i].real();
        out(i, 1) = z[i].imag();
    }
    return out;
}

